            ImmutableArray<string> ids,

            string instanceId,

            string? outputFile,

            string? query,

            string? ruleType,

            ImmutableArray<Outputs.GetDefenseRulesRuleResult> rules)
        {
            DefenseType = defenseType;
            EnableDetails = enableDetails;
            Id = id;
            Ids = ids;
            InstanceId = instanceId;
            OutputFile = outputFile;
            Query = query;
            RuleType = ruleType;
            Rules = rules;
        }
    }
}
